const INDEX=new Map(),VISUAL_INDEX=new Map();for(const item of TOWER_ASSETS){const key=`${item.region}:${item.category}`;if(!INDEX.has(key))INDEX.set(key,[]);INDEX.get(key).push(item);const visualKey=`${item.region}:${item.tileRole}`;if(!VISUAL_INDEX.has(visualKey))VISUAL_INDEX.set(visualKey,[]);VISUAL_INDEX.get(visualKey).push(item);}
export function towerAssets(region,category=null){if(category)return INDEX.get(`${region}:${category}`)||[];return TOWER_ASSETS.filter((item)=>item.region===region);}
export function towerVisualAssets(region,tileRole=null){if(tileRole)return VISUAL_INDEX.get(`${region}:${tileRole}`)||[];return TOWER_ASSETS.filter((item)=>item.region===region);}
